import React, { useState, useEffect } from 'react';
import axios from 'axios';
import ThemeToggle from './ThemeToggle';
import './App.css';
import Editor from "@monaco-editor/react";

function App() {
  const [files, setFiles] = useState(() => {
    const savedFiles = localStorage.getItem("files");
    return savedFiles
      ? JSON.parse(savedFiles)
      : [
          {
            id: 1,
            filename: "index.html",
            content: `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Saurabh IDE</title>
  <link rel="stylesheet" href="index.css" />
</head>
<body>
  <div class="container">
    <h1 id="title">Hello Coder</h1>
    <p class="subtitle">Welcome to your coding playground</p>
    <p class="author">by Saurabh Singh</p>
    <button id="btn">Start Coding</button>
  </div>
  <script src="index.js"></script>
</body>
</html>`
          },
          {
            id: 2,
            filename: "index.css",
            content: `* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  min-height: 100vh;
  display: flex;
  justify-content: center;
  align-items: center;
  background: linear-gradient(135deg, #0f172a, #1e293b);
  color: white;
  font-family: Inter, Arial, sans-serif;
}

.container {
  text-align: center;
  padding: 40px;
}

h1 {
  font-size: 3rem;
  margin-bottom: 15px;
  background: linear-gradient(90deg, #38bdf8, #818cf8);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}

.subtitle {
  font-size: 1.2rem;
  color: #cbd5e1;
}

.author {
  margin-top: 10px;
  color: #94a3b8;
}

button {
  margin-top: 30px;
  padding: 14px 28px;
  border: none;
  border-radius: 10px;
  background: #3b82f6;
  color: white;
  font-size: 1rem;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
}

button:hover {
  transform: translateY(-3px);
  background: #2563eb;
  box-shadow: 0 10px 25px rgba(59, 130, 246, 0.35);
}`
          },
          {
            id: 3,
            filename: "index.js",
            content: `const btn = document.getElementById("btn");
const title = document.getElementById("title");

btn.addEventListener("click", () => {
  title.textContent = "Happy Coding";
  btn.textContent = "Let's Build";
});`
          }
        ];
  });

  const [activeFileId, setActiveFileId] = useState(() => {
    const saved = localStorage.getItem("activeFileID");
    return saved ? Number(saved) : null;
  });
  
  const [showCreateInput, setShowCreateInput] = useState(false);
  const [newFileName, setNewFileName] = useState("");
  const [code, setCode] = useState("");
  const [showFiles, setShowFiles] = useState(true);
  const [showAI, setShowAI] = useState(true);
  const [prompt, setPrompt] = useState('');
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(false);
  const [theme, setTheme] = useState(localStorage.getItem("theme") || "dark");
  const [aiMode, setAiMode] = useState('chat'); // 'chat' or 'generate'

  const activeFile = files.find(file => file.id === activeFileId);

  // Set active file ID when files load
  useEffect(() => {
    if (files.length > 0 && activeFileId === null) {
      setActiveFileId(files[0].id);
    }
  }, [files, activeFileId]);

  // Save active file ID to localStorage
  useEffect(() => {
    if (activeFileId !== null) {
      localStorage.setItem("activeFileID", activeFileId);
    }
  }, [activeFileId]);

  // Update code when active file changes
  useEffect(() => {
    const activeFile = files.find(file => file.id === activeFileId);
    if (activeFile) {
      setCode(activeFile.content);
    } else if (files.length > 0) {
      setCode(files[0].content);
    } else {
      setCode("// Write your code here");
    }
  }, [files, activeFileId]);

  // Save files to localStorage
  useEffect(() => {
    localStorage.setItem("files", JSON.stringify(files));
  }, [files]);

  // Handle Chat mode - just conversation, no code modification
  const handleChat = async () => {
    if (!prompt.trim()) {
      setMessages((prev) => [
        ...prev,
        {
          type: 'error',
          text: 'Please enter a message!',
          mode: 'chat'
        }
      ]);
      return;
    }

    const userMessage = {
      type: 'user',
      text: prompt,
      mode: 'chat'
    };

    setMessages((prev) => [...prev, userMessage]);
    const currentPrompt = prompt;
    setPrompt('');
    setLoading(true);

    const requestPayload = {
      message: currentPrompt,
      mode: 'chat'
    };

    console.log('📤 Sending Chat Request:', JSON.stringify(requestPayload, null, 2));

    try {
      const response = await axios.post(
        'http://localhost:5000/api/chat',
        requestPayload
      );

      console.log('✅ Chat Response Received');
      console.log('📥 Response Data:', response.data);

      const aiMessage = {
        type: 'ai',
        text: response.data.reply,
        mode: 'chat'
      };

      setMessages((prev) => [...prev, aiMessage]);
      console.log('✅ Chat UI Updated');
    } catch (err) {
      console.error('❌ ERROR:', err);
      const errorMessage = {
        type: 'error',
        text: `Error: ${err.response?.data?.error || err.message}`,
        mode: 'chat'
      };
      setMessages((prev) => [...prev, errorMessage]);
    } finally {
      setLoading(false);
      console.log('========== CHAT REQUEST COMPLETE ==========\n');
    }
  };

  // Handle Generate Code mode - improves/modifies current code
  const handleGenerateCode = async () => {
    if (!prompt.trim()) {
      setMessages((prev) => [
        ...prev,
        {
          type: 'error',
          text: 'Please enter a prompt for code generation!',
          mode: 'generate'
        }
      ]);
      return;
    }

    const userMessage = {
      type: 'user',
      text: prompt,
      mode: 'generate'
    };

    setMessages((prev) => [...prev, userMessage]);
    const currentPrompt = prompt;
    setPrompt('');
    setLoading(true);

    const requestPayload = {
      code: code,
      prompt: currentPrompt,
      mode: 'generate'
    };

    console.log('📤 Sending Code Generation Request:', JSON.stringify(requestPayload, null, 2));

    try {
      const response = await axios.post(
        'http://localhost:5000/api/generate-code',
        requestPayload
      );

      console.log('✅ Code Generation Response Received');
      console.log('📥 Response Data:', response.data);

      const generatedCode = response.data.generatedCode;
      
      // Only update the code if it's not null/undefined
      if (generatedCode) {
        setCode(generatedCode);

        // Save the generated code to the current file
        setFiles(prev =>
          prev.map(file =>
            file.id === activeFileId
              ? { ...file, content: generatedCode }
              : file
          )
        );

        const aiMessage = {
          type: 'ai',
          text: 'Code generated/updated successfully!',
          mode: 'generate',
          code: generatedCode
        };

        setMessages((prev) => [...prev, aiMessage]);
      } else {
        throw new Error('No code generated');
      }
      
      console.log('✅ Code Generation UI Updated');
    } catch (err) {
      console.error('❌ ERROR:', err);
      const errorMessage = {
        type: 'error',
        text: `Error generating code: ${err.response?.data?.error || err.message}`,
        mode: 'generate'
      };
      setMessages((prev) => [...prev, errorMessage]);
    } finally {
      setLoading(false);
      console.log('========== CODE GENERATION REQUEST COMPLETE ==========\n');
    }
  };

  // Main submit handler based on selected mode
  const handleSubmit = () => {
    if (aiMode === 'chat') {
      handleChat();
    } else {
      handleGenerateCode();
    }
  };

  const createFile = () => {
    if (!newFileName.trim()) return;

    const newFile = {
      id: Date.now(),
      filename: newFileName,
      content: ""
    };

    setFiles((prev) => [...prev, newFile]);
    setActiveFileId(newFile.id);
    setNewFileName("");
    setShowCreateInput(false);
  };

  const handleFileClick = (fileId) => {
    const file = files.find(f => f.id === fileId);
    if (file) {
      setActiveFileId(fileId);
      setCode(file.content);
    }
  };

  const saveCurrentFile = () => {
    setFiles(prev =>
      prev.map(file =>
        file.id === activeFileId
          ? { ...file, content: code }
          : file
      )
    );
    // Show temporary success message
    const successMessage = {
      type: 'ai',
      text: '✅ File saved successfully!',
      mode: 'system'
    };
    setMessages((prev) => [...prev, successMessage]);
    setTimeout(() => {
      setMessages((prev) => prev.filter(msg => msg.text !== '✅ File saved successfully!'));
    }, 2000);
  };

  const deleteFile = (fileId) => {
    if (files.length === 1) {
      alert("Cannot delete the last file");
      return;
    }
    
    setFiles(prev => prev.filter(file => file.id !== fileId));
    
    if (activeFileId === fileId) {
      const remainingFiles = files.filter(file => file.id !== fileId);
      if (remainingFiles.length > 0) {
        setActiveFileId(remainingFiles[0].id);
      }
    }
  };

  const runHtml = () => {
    if (!activeFile) return;

    let finalHtml = activeFile.content;

    // Replace CSS files
    const cssMatches = [
      ...finalHtml.matchAll(/<link[^>]*href=["']([^"']+)["'][^>]*>/gi)
    ];

    cssMatches.forEach((match) => {
      const filePath = match[1];
      const fileName = filePath.split("/").pop();
      const cssFile = files.find(
        (f) => f.filename.toLowerCase() === fileName.toLowerCase()
      );

      if (cssFile) {
        finalHtml = finalHtml.replace(
          match[0],
          `<style>\n${cssFile.content}\n</style>`
        );
      }
    });

    // Replace JS files
    const jsMatches = [
      ...finalHtml.matchAll(/<script[^>]*src=["']([^"']+)["'][^>]*><\/script>/gi)
    ];

    jsMatches.forEach((match) => {
      const filePath = match[1];
      const fileName = filePath.split("/").pop();
      const jsFile = files.find(
        (f) => f.filename.toLowerCase() === fileName.toLowerCase()
      );

      if (jsFile) {
        finalHtml = finalHtml.replace(
          match[0],
          `<script>\n${jsFile.content}\n<\/script>`
        );
      }
    });

    // Create preview
    const blob = new Blob([finalHtml], { type: "text/html" });
    const previewUrl = URL.createObjectURL(blob);
    window.open(previewUrl, "_blank", "noopener,noreferrer");

    // Memory cleanup
    setTimeout(() => {
      URL.revokeObjectURL(previewUrl);
    }, 10000);
  };

  const getLanguage = (fileName) => {
    const ext = fileName?.split(".").pop()?.toLowerCase();

    switch (ext) {
      case "html":
        return "html";
      case "js":
        return "javascript";
      case "css":
        return "css";
      case "json":
        return "json";
      case "ts":
        return "typescript";
      default:
        return "plaintext";
    }
  };

  const clearMessages = () => {
    setMessages([]);
  };

  return (
    <div className="app-container">
      {/* FILE EXPLORER */}
      {showFiles && (
        <div className="file-sidebar">
          <div className="panel-header">
            <h3>📁 File Structure</h3>
          </div>

          <div className="file-tree">
            <div
              style={{
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center',
                marginBottom: '10px'
              }}
            >
              <div>📁 src</div>
              <button
                onClick={() => setShowCreateInput(true)}
                className="add-file-btn"
                style={{
                  background: 'none',
                  border: 'none',
                  cursor: 'pointer',
                  fontSize: '18px'
                }}
              >
                ➕
              </button>
            </div>

            {showCreateInput && (
              <input
                type="text"
                placeholder="File name..."
                value={newFileName}
                onChange={(e) => setNewFileName(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === "Enter") {
                    createFile();
                  }
                }}
                onBlur={() => {
                  if (!newFileName.trim()) {
                    setShowCreateInput(false);
                  }
                }}
                autoFocus
                style={{
                  width: '100%',
                  padding: '5px',
                  marginBottom: '10px',
                  borderRadius: '4px',
                  border: '1px solid #ccc'
                }}
              />
            )}

            <div style={{ paddingLeft: '18px' }}>
              {files.map((file) => (
                <div
                  key={file.id}
                  className={`file-item ${activeFileId === file.id ? 'active' : ''}`}
                  style={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    cursor: 'pointer',
                    padding: '8px 5px',
                    backgroundColor: activeFileId === file.id ? '#e0e0e0' : 'transparent',
                    borderRadius: '4px',
                    marginBottom: '2px'
                  }}
                >
                  <span 
                    onClick={() => handleFileClick(file.id)}
                    style={{ flex: 1 }}
                  >
                    📄 {file.filename}
                  </span>
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      deleteFile(file.id);
                    }}
                    style={{
                      background: 'none',
                      border: 'none',
                      cursor: 'pointer',
                      color: 'red',
                      fontSize: '14px',
                      padding: '0 5px'
                    }}
                  >
                    ✖
                  </button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* CODE EDITOR */}
      <div className="editor-panel">
        <div className="panel-header">
          <div
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: '10px'
            }}
          >
            <button
              className="toggle-btn"
              onClick={() => setShowFiles(!showFiles)}
              style={{
                padding: '5px 10px',
                cursor: 'pointer',
                borderRadius: '4px',
                border: 'none'
              }}
            >
              ☰
            </button>

            <button
              className="toggle-btn"
              onClick={() => setShowAI(!showAI)}
              style={{
                padding: '5px 10px',
                cursor: 'pointer',
                borderRadius: '4px',
                border: 'none'
              }}
            >
              🤖
            </button>

            <h3>Code Editor</h3>
          </div>

          <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
            <button
              onClick={saveCurrentFile}
              style={{
                padding: '5px 10px',
                backgroundColor: '#4CAF50',
                color: 'white',
                border: 'none',
                borderRadius: '4px',
                cursor: 'pointer'
              }}
            >
              💾 Save
            </button>
            <button
              onClick={runHtml}
              style={{
                padding: '5px 10px',
                backgroundColor: activeFile?.filename?.toLowerCase().endsWith(".html") ? '#2196F3' : '#ccc',
                color: 'white',
                border: 'none',
                borderRadius: '4px',
                cursor: activeFile?.filename?.toLowerCase().endsWith(".html") ? 'pointer' : 'not-allowed'
              }}
              disabled={!activeFile?.filename?.toLowerCase().endsWith(".html")}
            >
              ▶ Run
            </button>
            <ThemeToggle onThemeChange={setTheme} />
          </div>
        </div>

        <Editor
          height="calc(100vh - 60px)"
          language={getLanguage(activeFile?.filename)}
          theme={theme === "light" ? "vs-light" : "vs-dark"}
          value={code}
          onChange={(value) => {
            setCode(value || "");
          }}
          options={{
            minimap: { enabled: false },
            fontSize: 14,
            wordWrap: 'on'
          }}
        />
      </div>

      {/* AI PANEL */}
      {showAI && (
        <div className="chat-panel">
          <div className="panel-header">
            <h3>🤖 AI Assistant</h3>
            <div style={{ display: 'flex', gap: '5px' }}>
              <button
                onClick={clearMessages}
                style={{
                  background: 'none',
                  border: 'none',
                  cursor: 'pointer',
                  fontSize: '16px',
                  padding: '5px'
                }}
                title="Clear chat"
              >
                🗑️
              </button>
              <button
                className="toggle-btn"
                onClick={() => setShowAI(false)}
                style={{
                  background: 'none',
                  border: 'none',
                  cursor: 'pointer',
                  fontSize: '18px'
                }}
              >
                ✖
              </button>
            </div>
          </div>

          {/* Mode Selector Toggle */}
          <div style={{
            display: 'flex',
            padding: '10px',
            gap: '10px',
            borderBottom: '1px solid #e0e0e0',
            backgroundColor: theme === 'light' ? '#f5f5f5' : '#2d2d2d'
          }}>
            <button
              onClick={() => setAiMode('chat')}
              style={{
                flex: 1,
                padding: '8px',
                backgroundColor: aiMode === 'chat' ? (theme === 'light' ? '#2196F3' : '#1976D2') : (theme === 'light' ? '#e0e0e0' : '#424242'),
                color: aiMode === 'chat' ? 'white' : (theme === 'light' ? '#333' : '#ccc'),
                border: 'none',
                borderRadius: '6px',
                cursor: 'pointer',
                fontWeight: 'bold',
                transition: 'all 0.3s ease'
              }}
            >
              💬 Chat
            </button>
            <button
              onClick={() => setAiMode('generate')}
              style={{
                flex: 1,
                padding: '8px',
                backgroundColor: aiMode === 'generate' ? (theme === 'light' ? '#4CAF50' : '#388E3C') : (theme === 'light' ? '#e0e0e0' : '#424242'),
                color: aiMode === 'generate' ? 'white' : (theme === 'light' ? '#333' : '#ccc'),
                border: 'none',
                borderRadius: '6px',
                cursor: 'pointer',
                fontWeight: 'bold',
                transition: 'all 0.3s ease'
              }}
            >
              ⚡ Generate Code
            </button>
          </div>

          <div className="chat-messages" style={{
            flex: 1,
            overflowY: 'auto',
            padding: '15px',
            display: 'flex',
            flexDirection: 'column',
            gap: '10px'
          }}>
            {messages.length === 0 ? (
              <div className="empty-chat" style={{
                textAlign: 'center',
                color: theme === 'light' ? '#666' : '#aaa',
                padding: '20px'
              }}>
                <p>👋 Hi! I'm your AI code assistant.</p>
                <p>Select a mode and start interacting!</p>
                <hr style={{ margin: '10px 0' }} />
                <p><strong>💬 Chat Mode:</strong> Just conversation, ask me anything about coding!</p>
                <p><strong>⚡ Generate Code Mode:</strong> I'll generate/improve code based on your prompt</p>
              </div>
            ) : (
              messages.map((msg, idx) => (
                <div 
                  key={idx} 
                  className={`message ${msg.type}`}
                  style={{
                    padding: '10px',
                    borderRadius: '8px',
                    backgroundColor: msg.type === 'user' 
                      ? (theme === 'light' ? '#e3f2fd' : '#1e3a5f')
                      : msg.type === 'ai' 
                        ? (theme === 'light' ? '#f3e5f5' : '#4a148c')
                        : (theme === 'light' ? '#ffebee' : '#5c1a1a'),
                    alignSelf: msg.type === 'user' ? 'flex-end' : 'flex-start',
                    maxWidth: '85%'
                  }}
                >
                  <div className="message-label" style={{
                    fontWeight: 'bold',
                    fontSize: '11px',
                    marginBottom: '5px',
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center'
                  }}>
                    <span>
                      {msg.type === 'user' ? '👤 You' : msg.type === 'ai' ? '🤖 AI' : '⚠️ Error'}
                    </span>
                    {msg.mode && (
                      <span style={{
                        fontSize: '10px',
                        padding: '2px 6px',
                        borderRadius: '4px',
                        backgroundColor: msg.mode === 'chat' ? '#2196F3' : '#4CAF50',
                        color: 'white',
                        marginLeft: '8px'
                      }}>
                        {msg.mode === 'chat' ? '💬 Chat' : '⚡ Generate'}
                      </span>
                    )}
                  </div>
                  <div className="message-text" style={{
                    fontSize: '13px',
                    lineHeight: '1.5',
                    wordWrap: 'break-word'
                  }}>
                    {msg.text}
                  </div>
                </div>
              ))
            )}

            {loading && (
              <div className="message ai" style={{
                padding: '10px',
                borderRadius: '8px',
                backgroundColor: theme === 'light' ? '#f3e5f5' : '#4a148c',
                alignSelf: 'flex-start',
                maxWidth: '85%'
              }}>
                <div className="message-label" style={{
                  fontWeight: 'bold',
                  fontSize: '11px',
                  marginBottom: '5px'
                }}>
                  🤖 AI ({aiMode === 'chat' ? 'Chat' : 'Generate Code'})
                </div>
                <div className="message-text loading">Thinking...</div>
              </div>
            )}
          </div>

          <div className="chat-input-section" style={{
            padding: '15px',
            borderTop: `1px solid ${theme === 'light' ? '#e0e0e0' : '#424242'}`,
            display: 'flex',
            gap: '10px'
          }}>
            <input
              type="text"
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              placeholder={aiMode === 'chat' 
                ? "Ask me anything about coding..." 
                : "Describe what code you want me to generate/improve..."}
              disabled={loading}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !loading) {
                  handleSubmit();
                }
              }}
              style={{
                flex: 1,
                padding: '10px',
                borderRadius: '4px',
                border: `1px solid ${theme === 'light' ? '#ccc' : '#555'}`,
                fontSize: '14px',
                backgroundColor: theme === 'light' ? 'white' : '#1e1e1e',
                color: theme === 'light' ? '#333' : '#ddd'
              }}
            />
            <button 
              onClick={handleSubmit} 
              disabled={loading || !prompt.trim()}
              style={{
                padding: '10px 20px',
                backgroundColor: loading || !prompt.trim() 
                  ? '#ccc' 
                  : aiMode === 'chat' 
                    ? '#2196F3' 
                    : '#4CAF50',
                color: 'white',
                border: 'none',
                borderRadius: '4px',
                cursor: loading || !prompt.trim() ? 'not-allowed' : 'pointer',
                fontWeight: 'bold'
              }}
            >
              {loading ? '⏳' : aiMode === 'chat' ? '💬 Send' : '⚡ Generate'}
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
